// <![CDATA[
// 今日の日付を取得
var today = new Date();
 
// 開催日を設定
// ※ 月は0～11までで指定
var targetDay = new Date(2017,2,25);
 
// 1日のマイクロ秒で除算をすると
// 開催日までの日数が算出できる
remainDay = Math.floor((targetDay - today) / (24*60*60*1000));
 
// 開催前日の場合は残り0日になってしまうのを防止
remainDay++;
 
if (remainDay > 0) {
  document.write("あと"+remainDay+"日");
}
else if (remainDay < -1) {
  document.write("あと"+remainDay+"日");
}
else {
  document.write("あと"+remainDay+"日");
}
// ]]>